	.TITLE	SPL	.PROC	M68000		; mnemonics calm-3	.BASE	10.		; base 10 par defaut	.LISTHEX		; listing en hexadecimal	.REF	SM8		; def diverses	.REF	NTREL		; def noyau temps reel	.REF	GESMEM		; def gestionnaire de memoire	.REF	FOS		; def file operating system	.REF	LIB		; def librairie	.REF	DRIVERS		; def drivers; CONSTANTES; ----------NBMAX	=	200; VARIABLES; ---------	.LOC	0NBPOINTS: .BLK.32	1	; nombre de points de donnesPX	: .BLK.32	NBMAX	; position des points de donnesPY	: .BLK.32	NBMAXFANION	: .BLK.32	1PARAM2	: .BLK.32	NBMAX	; paramtre au carr ou t**2PARAM	: .BLK.32	NBMAX	; paramtre ou tTAMPON	: .BLK.32	1	; zone tamponTAMPO	: .BLK.32	1	; zone tamponTAMP	: .BLK.32	1	; zone tamponAX	: .BLK.32	NBMAX	; coefficients intermdiairesAY	: .BLK.32	NBMAX	; coefficients intermdiairesBX	: .BLK.32	NBMAX	; coefficients intermdiairesBY	: .BLK.32	NBMAX	; coefficients intermdiairesSIGNE	: .BLK.32	1	; 0 => positif ; 1 => ngatifPENTEX	: .BLK.32	NBMAX	; pentes aux points de donnes, coord. XPENTEY	: .BLK.32	NBMAX	; pentes aux points de donnes, coord. YCO1X	: .BLK.32	1	; coeff. pour le calc. des pentes, cas cyc.CO1Y	: .BLK.32	1	; idemCO2X	: .BLK.32	NBMAX	; idemCO2Y	: .BLK.32	NBMAX	; idemCO3	: .BLK.32	NBMAX	; idemK1X	: .BLK.32	NBMAX	; idemK1Y	: .BLK.32	NBMAX	; idemK2	: .BLK.32	NBMAX	; idemK3	: .BLK.32	NBMAX	; idemCK1	: .BLK.32	NBMAX	; idemCK2X	: .BLK.32	NBMAX	; idemCK2Y	: .BLK.32	NBMAX	; idemAKX	: .BLK.32	NBMAX	; coeff. pour le terme d'ordre 3 du polynomeAKY	: .BLK.32	NBMAX	; coeff. pour le terme d'ordre 3 du polynomeBKX	: .BLK.32	NBMAX	; coeff. pour le terme d'ordre 2 du polynomeBKY	: .BLK.32	NBMAX	; coeff. pour le terme d'ordre 2 du polynomePAS	: .BLK.32	1	; pas pour le calcul de la splineDX1	: .BLK.32	1DX2	: .BLK.32	1DX3	: .BLK.32	1DY1	: .BLK.32	1DY2	: .BLK.32	1DY3	: .BLK.32	1PTX	: .BLK.32	1	; point interpol en X (32|0)PTY	: .BLK.32	1	; point interpol en Y (32|0)COPIX	: .BLK.32	1	; comme PTX (12|20)COPIY	: .BLK.32	1	; comme PTY (12|20)COMPT	: .BLK.32	1	; compte le nombre de points a afficherSA4	: .BLK.32	1	; sauve A4T0	: .BLK.32	1	; mm. tamp.T1	: .BLK.32	1	; mm. tamp.T2	: .BLK.32	1	; mm. tamp.T3	: .BLK.32	1	; mm. tamp.T4	: .BLK.32	1	; mm. tamp.T5	: .BLK.32	1	; mm. tamp.T6	: .BLK.32	1	; mm. tamp.T7	: .BLK.32	1	; mm. tamp.BUFFER	: .BLK.8	10	; bufferLGVAR	:                                                              ; PROGRAMME; ---------	.LOC	0START:	.16	LIB,?OPELIB	; ouvre la librairie	MOVE.32	#LGVAR,D4	MOVE.16	#MTYPCP,D1	.16	GESMEM,?GETMEM	; demande memoire pour var.	JUMP,NE	FIN	MOVE.32	A4,A6		; A6 <-- ^variables	DEC.32	D410$:	CLR.8	{A4+}	DECJ.16,NMO D4,10$	.16	LIB,?AFTIM	.ASCIZE	"<CR>SPLINE<CR><CR>"	.16	LIB,?GETCAR	MOVE.32	#100,{A6}+PX+0	MOVE.32	#100,{A6}+PY+0	MOVE.32	#100,{A6}+PX+4	MOVE.32	#200,{A6}+PY+4	MOVE.32	#200,{A6}+PX+8	MOVE.32	#200,{A6}+PY+8	MOVE.32	#200,{A6}+PX+12	MOVE.32	#100,{A6}+PY+12	MOVE.32	#100,{A6}+PX+16	MOVE.32	#100,{A6}+PY+16	MOVE.32	#20,{A6}+NBPOINTS	CALL	SPLINE_NAT	.16	LIB,?AFTIM	.ASCIZE	"C'est fini ..."	.16	LIB,?GETCARFIN:	.16	LIB,?CLOLIB	; ferme la librairie	.16	FOS,?STOP	; avorte le processus ...;-----------\; SPLINE_NAT >	calcule la spline naturelle;===========/;;;in :rien;out:rien;mod:FSPLINE_NAT:	CALL	CALCPAR		; calcul des paramtres	COMP.32	#16.,{A6}+NBPOINTS; min 4 points ?	JUMP,LO	90$	CALL	INCYC		; calc des coef. initiaux CO1,CO2[i],CO3[i]	CALL	CALCK		; calcul de K1X[n-1],K1Y[n-1],K2[n-1]	CALL	CALCKS		; calcul les coef. K1X,K2,K3,CK1 et CK2	CALL	PENTEIC		; calc. PENTE[0],PENTE[n], cond. cyclique	CALL	PENTENC		; calcul les PENTEX[i] et PENTEY[i]	CALL	CALCAK		; calcul des coef. du polynme, AKX et AKY	CALL	CALCBK		; calcul des coef. du polynme, BKX et BKY	CALL	CALCPT		; calcul des points d'interpolation90$:	RET;-----------\; SPLINE_CYL >	calcule la spline cylindrique;===========/;;;in :rien;out:rien;mod:FSPLINE_CYL:	CALL	CALCPAR		; calcul des paramtres	CALL	A0ETB0		; calcul les coefficients A[0] et B[0]	COMP.32	#8.,{A6}+NBPOINTS; min 2 points ?	JUMP,LO	90$	CALL	AIETBI		; calcul les AX[i] ,AY[i],BX[i] et BY[i]	CALL	PENTEN		; calcul la pente au dernier point PENTE[n]	CALL	PENTEI		; calcul la pente aux autres points	CALL	CALCAK		; calcul des coef. du polynme, AKX et AKY	CALL	CALCBK		; calcul des coef. du polynme, BKX et BKY	CALL	CALCPT		; calcul des points d'interpolation90$:	RET;--------\; CALCPAR > 	calcul des paramtres de la spline;--------/;;;in : rien;out: rien;mod: FCALCPAR:	MOVE.32	#0,D0		; D0 <-- i=0	MOVE.32	#{A6}+PARAM2,A0	MOVE.32	#0,{A0}+{D0}	; PARAM2[0] <-- 0	MOVE.32	#{A6}+PARAM,A0	MOVE.32	#0,{A0}+{D0}	; PARAM[0] <-- 01$:	MOVE.32	#{A6}+PX,A0	MOVE.32	{A0}+{D0},D1	; D1 <-- PX[i]	MOVE.32	#{A6}+PY,A0	MOVE.32	{A0}+{D0},D2	; D2 <-- PY[i]	ADD.32	#4.,D0		; D0 <-- i=i+1	MOVE.32	{A0}+{D0},D4	; D4 <-- PY[i+1]	MOVE.32	#{A6}+PX,A0	MOVE.32	{A0}+{D0},D3	; D3 <-- PX[i+1]	SUB.32	D1,D3		; D3 <-- PX[i+1]-PX[i]	MUL.A16	D3,D3		; D3 <-- (PX[i+1]-PX[i])**2	SUB.32	D2,D4		; D4 <-- PY[i+1]-PY[i]	MUL.A16	D4,D4		; D4 <-- (PY[i+1]-PY[i])**2	ADD.32	D3,D4		; D4 <-- D3+D4	MOVE.32	#{A6}+PARAM2,A0	MOVE.32	D4,{A0}+{D0}	; PARAM2 <-- D4	COMP.32	{A6}+NBPOINTS,D0; a-t-on tous les paramtres	JUMP,LT	1$		; NON => recommence	CALL	EFFRAC		; effectue les racines de tous les paramtres	RET;-------\; A0ETB0 >	calcul les coefficients intermdiaires A[0] et B[0];-------/;;;in : rien;out: rien;mod: FA0ETB0:	MOVE.32	#0,D0		; D0 <-- i=0	MOVE.32	#{A6}+PX,A0	MOVE.32	{A0}+{D0},D3	; D3 <-- PX[0]	MOVE.32	#{A6}+PY,A0	MOVE.32	{A0}+{D0},D4	; D4 <-- PY[0]	ADD.32	#4.,D0		; D0 <-- i=i+1	MOVE.32	{A0}+{D0},D2	; D2 <-- PY[1]	MOVE.32	#{A6}+PX,A0	MOVE.32	{A0}+{D0},D1	; D1 <-- PX[1]	MOVE.32	#{A6}+PARAM,A0	MOVE.32	{A0}+{D0},D6	; D6 <-- PARAM[1]	"format"	SUB.32	D3,D1		; D1 <-- PX[1]-PX[0]	SUB.32	D4,D2		; D2 <-- PY[1]-PY[0]	MOVE.32	#H'30000,D3	; D3 <-- 3 format	SR.32	#1,D3		; D3 <-- 3/2 format	PUSH.32	D3		; sauve 3/2 format	CLR.32	D5	MOVE.32 D1,D4	MOVE.32	D1,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; SIGNE positif ?	JUMP,EQ	10$		; OUI => on ne fait rien	NEG.32	D4		; NON => prendre la ngation	10$:	CALL	MUL64		; D4 <-- (3/2)*(PX[1]-PX[0]) format	CLR.32	D5	MOVE.32	#65536.,D3	; prparation pour la division par PARAM[1]	CALL	MUL64	MOVE.32	D6,D3	CALL	DIV64		; D4 <-- (3*(PX[1]-PX[0])/(2*PARAM[1])	CLR.32	D0		; D0 <-- i=0	COMP.32	#0,{A6}+SIGNE	; si SIGNE est positif	JUMP,EQ	20$		; OUI => on ne fait rien	NEG.32	D4		; NON => prendre la ngation20$:	MOVE.32	#{A6}+AX,A0	MOVE.32	D4,{A0}+{D0}	; AX[0] <-- D4 format	MOVE.32	D2,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; SIGNE positif ?	JUMP,EQ	30$		; OUI => on ne fait rien	NEG.32	D2		; NON => prendre la ngation30$:	POP.32	D3		; sort 3/2 format	CLR.32	D5	MOVE.32	D2,D4	CALL	MUL64		; D4 <-- (3/2)*(PY[1]-PY[0]) format	CLR.32	D5	MOVE.32	#65536.,D3	CALL	MUL64		; prparation pour la division par PARAM[1]	MOVE.32	D6,D3	CALL	DIV64		; D4 <-- (3*(PY[1]-PY[0])/(2*PARAM[1])	COMP.32	#0,{A6}+SIGNE	; SIGNE positif ?	JUMP,EQ	40$		; OUI => on ne fait rien	NEG.32	D4		; NON => prendre la ngation40$:	MOVE.32	#{A6}+AY,A0	MOVE.32	D4,{A0}+{D0}	; AY[0] <-- D4 format	MOVE.32	#H'8000,D1	; D1 <-- 1/2 format	MOVE.32	#{A6}+BX,A0	MOVE.32	D1,{A0}+{D0}	; BX[0] <-- 1/2 format	MOVE.32	#{A6}+BY,A0	MOVE.32	D1,{A0}+{D0}	; BY[0] <-- 1/2 format	RET;-------\; AIETBI >	calcul des coefficients intermdiaires AX[i] et AY[i];-------/;;;in : rien;out: rien;mod: FAIETBI:	MOVE.32	#4.,D0		; D0 <-- i=11$:	MOVE.32	#{A6}+PX,A0	MOVE.32	{A0}+{D0},{A6}+T3; T3 <-- PX[i] non format	MOVE.32	#{A6}+PARAM,A0	MOVE.32	{A0}+{D0},{A6}+T1; T1 <-- PARAM[i] format	ADD.32	#4.,D0		; D0 <-- i=i+1	MOVE.32	{A0}+{D0},{A6}+T2; T2 <-- PARAM[i+1] format	MOVE.32	#{A6}+PX,A0	MOVE.32	{A0}+{D0},{A6}+T4; T4 <-- PX[i+1] non format	SUB.32	#8.,D0		; D0 <-- i=i-1	MOVE.32	{A0}+{D0},{A6}+T5; T5 <-- PX[i-1]  non format	MOVE.32	#{A6}+AX,A0	MOVE.32	{A0}+{D0},{A6}+T6; T6 <-- AX[i-1]	MOVE.32	#{A6}+BX,A0	MOVE.32	{A0}+{D0},{A6}+T7; T7 <-- BX[i-1]	CALL	BI		; calcul BX[i]	ADD.32	#4.,D0		; D0 <-- i	MOVE.32	#{A6}+BX,A0	MOVE.32	{A6}+TAMP,{A0}+{D0}; BX[i] <-- D4 	CALL	AI		; calcul AX[i]	MOVE.32	#{A6}+AX,A0	MOVE.32	{A6}+TAMP,{A0}+{D0}; AX[i] <-- D4 	MOVE.32	#{A6}+PY,A0	MOVE.32	{A0}+{D0},{A6}+T3; T3 <-- PY[i] non format	MOVE.32	#{A6}+PARAM,A0	MOVE.32	{A0}+{D0},{A6}+T1; T1 <-- PARAM[i] format	ADD.32	#4.,D0		; D0 <-- i=i+1	MOVE.32	{A0}+{D0},{A6}+T2; T2 <-- PARAM[i+1] format	MOVE.32	#{A6}+PY,A0	MOVE.32	{A0}+{D0},{A6}+T4; T4 <-- PY[i+1] non format	SUB.32	#8.,D0		; D0 <-- i=i-1	MOVE.32	{A0}+{D0},{A6}+T5; T5 <-- PY[i-1]	MOVE.32	#{A6}+AY,A0	MOVE.32	{A0}+{D0},{A6}+T6; T6 <-- AY[i-1]	MOVE.32	#{A6}+BY,A0	MOVE.32	{A0}+{D0},{A6}+T7; T7 <-- BY[i-1]	CALL	BI		; calcul BY[i]	ADD.32	#4.,D0		; D0 <-- i	MOVE.32	#{A6}+BY,A0	MOVE.32	{A6}+TAMP,{A0}+{D0}; BY[i] <-- D4 	CALL	AI		; calcul AY[i]	MOVE.32	#{A6}+AY,A0	MOVE.32	{A6}+TAMP,{A0}+{D0}; AY[i] <-- D4 	ADD.32	#4.,D0		; D0 <-- i=i+1	MOVE.32	{A6}+NBPOINTS,D1	SUB.32	#4.,D1	COMP.32	D1,D0		; test si n-1 coefficients sont calculs	JUMP,LT	1$	RET;-------\; PENTEN >	calcul de la tangeante au dernier point;-------/;;;in : rien;out: rien;mod: FPENTEN:	MOVE.32	{A6}+NBPOINTS,D0	SUB.32	#4.,D0		; D0 <-- i=n	MOVE.32	#{A6}+PARAM,A0	MOVE.32	{A0}+{D0},D6	; D6 <-- PARAM[n]	MOVE.32	#{A6}+PX,A0	MOVE.32	{A0}+{D0},D1	; D1 <-- PX[n]	MOVE.32	#{A6}+PY,A0	MOVE.32	{A0}+{D0},D2	; D2 <-- PY[n]	SUB.32	#4.,D0		; D0 <-- i=n-1	SUB.32	{A0}+{D0},D2	; D2 <-- PY[n] - PY[n-1]	MOVE.32	#{A6}+PX,A0	SUB.32	{A0}+{D0},D1	; D1 <-- PX[n] - PX[n-1]	MUL.A16	#6.,D1		; D1 <-- 6 * (PX[n] - PX[n-1])	SL.32	#8,D1	 	; formatage de D1	SL.32	#8,D1	MUL.A16	#6.,D2		; D2 <-- 6 * (PY[n] - PY[n-1])	SL.32	#8,D2		; formatage de D2	SL.32	#8,D2	MOVE.32	D1,D3	MOVE.32	D3,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; SIGNE	positif ?	JUMP,EQ	10$		; OUI on ne fait rien	NEG.32	D310$:	MOVE.32	#65536.,D4	CLR.32	D5	CALL	MUL64		; formatage du numrateur	MOVE.32	D6,D3		; D3 <-- PARAM[n]	CALL	DIV64		; D4 <-- (6 * (PX[n]-PX[n-1])) / PARAM[n]	COMP.32	#0,{A6}+SIGNE	; non sign	JUMP,EQ	20$	NEG.32	D420$:	MOVE.32	D4,D1		; D1 <-- (6 * (PX[n] - PX[n-1])) / PARAM[n]	MOVE.32	D2,D3	MOVE.32	D3,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; SIGNE positif ?	JUMP,EQ	30$		; OUI => on ne fait rien	NEG.32	D3		; NON => prendre la ngation30$:	MOVE.32	#65536.,D4	CLR.32	D5	CALL	MUL64	MOVE.32	D6,D3		; D6 <-- PARAM[n]	CALL	DIV64	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	40$	NEG.32	D440$:	MOVE.32	D4,D2		; D2 <-- (6 * (PY[n] - PY[n-1])) / PARAM[n]	MOVE.32	#{A6}+AX,A0	MOVE.32	{A0}+{D0},D3	; D3 <-- AX[n-1]	SL.32	#1,D3		; D3 <-- 2 * AX[n-1]	SUB.32	D3,D1		; D1 <-- numrateur de PENTEX[n]	MOVE.32	#{A6}+AY,A0	MOVE.32	{A0}+{D0},D3	; D3 <-- AY[n-1]	SL.32	#1,D3		; D3 <-- 2 * AY[n-1]	SUB.32	D3,D2		; D2 <-- numrateur de PENTEY[n]	MOVE.32	#{A6}+BX,A0	MOVE.32	{A0}+{D0},D3	; D3 <-- BX[n-1]	SL.32	#1,D3		; D3 <-- 2 * BX[n-1]	MOVE.32	#H'40000,D6	; D6 <-- 4 format	SUB.32	D3,D6		; D6 <-- dnominteur de PENTEX[n]	MOVE.32	#0,{A6}+FANION	; initialise le fanion	MOVE.32	D1,D3		; D3 <-- numrateur	MOVE.32	D3,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; SIGNE positif ?	JUMP,EQ	45$	NEG.32	D3	MOVE.32	#1,{A6}+FANION	; laisse une trace si ngatif45$:	MOVE.32	#65536.,D4	CLR.32	D5	CALL	MUL64	MOVE.32	D6,D3	MOVE.32	D3,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	50$	NEG.32	D3	COMP.32	#1,{A6}+FANION	JUMP,NE	48$	MOVE.32	#0,{A6}+FANION	; cas du num. et du dnom. ngatifs	JUMP	50$48$:	MOVE.32	#1,{A6}+FANION	; cas du num.>0 et du dnom.<050$:	CALL	DIV64		; D4 <-- PENTEX[n] non signe	COMP.32	#0,{A6}+FANION	; resultat positif ?	JUMP,EQ	55$		; OUI => sauve D4	NEG.32	D4		; NON => prendre la ngation de D455$:	ADD.32	#4.,D0		; D0 <-- i=n	MOVE.32	#{A6}+PENTEX,A0	MOVE.32	D4,{A0}+{D0}	; PENTEX[n] <-- D4	SUB.32	#4.,D0		; D0 <-- i=n-1	MOVE.32	#{A6}+BY,A0	MOVE.32	{A0}+{D0},D3	; D3 <-- BY[n-1]	SL.32	#1,D3		; D3 <-- 2 * BY[n-1]	MOVE.32	#H'40000,D6	; D6 <-- 4 format	SUB.32	D3,D6		; D6 <-- dnominateur de PENTEY[n]	MOVE.32	#0,{A6}+FANION	; initialise le fanion	MOVE.32	D2,D3		; D3 <-- numrateur	MOVE.32	D3,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; SIGNE positif ?	JUMP,EQ	60$	NEG.32	D3	MOVE.32	#1,{A6}+FANION	; laisse une trace si ngatif60$:	MOVE.32	#65536.,D4	CLR.32	D5	CALL	MUL64	MOVE.32	D6,D3	MOVE.32	D3,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	70$	NEG.32	D3	COMP.32	#1,{A6}+FANION	JUMP,NE	65$	MOVE.32	#0,{A6}+FANION	; cas du num. et du dnom. ngatifs	JUMP	70$65$:	MOVE.32	#1,{A6}+FANION	; cas du num.>0 et du dnom.<070$:	CALL	DIV64		; D4 <-- PENTEY[n] non signe	COMP.32	#0,{A6}+FANION	; resultat positif ?	JUMP,EQ	75$		; OUI => sauve D4	NEG.32	D4		; NON => prendre la ngation de D475$:	ADD.32	#4.,D0		; D0 <-- i=n	MOVE.32	#{A6}+PENTEY,A0	MOVE.32	D4,{A0}+{D0}	; PENTEY[n] <-- D4	RET;-------\; PENTEI >	calcul la pente aux n-1 points restant, n-1>= i >=0;-------/;;;in : rien;out: rien;mod: FPENTEI:	MOVE.32	{A6}+NBPOINTS,D0; D0 <-- NBPOINTS	SUB.32	#8.,D0		; D0 <-- i=n-11$:	MOVE.32	#{A6}+AX,A0	MOVE.32	{A0}+{D0},{A6}+T1; T1 <-- AX[i]	MOVE.32	#{A6}+BX,A0	MOVE.32	{A0}+{D0},{A6}+T2; T2 <-- BX[i]	ADD.32	#4.,D0		; DO <-- i=i+1	MOVE.32	#{A6}+PENTEX,A0	MOVE.32	{A0}+{D0},{A6}+T3; T3 <-- PENTEX[i+1]	CALL	DETPENT		; retourne PENTEX[i]	SUB.32	#4.,D0		; D0 <-- i	MOVE.32	#{A6}+PENTEX,A0	MOVE.32	{A6}+T4,{A0}+{D0}; PENTEX[i] <-- T4	MOVE.32	#{A6}+AY,A0	MOVE.32	{A0}+{D0},{A6}+T1; T1 <-- AY[i]	MOVE.32	#{A6}+BY,A0	MOVE.32	{A0}+{D0},{A6}+T2; T2 <-- BY[i]	ADD.32	#4.,D0		; DO <-- i=i+1	MOVE.32	#{A6}+PENTEY,A0	MOVE.32	{A0}+{D0},{A6}+T3; T3 <-- PENTEY[i+1]	CALL	DETPENT		; retourne PENTEY[i]	SUB.32	#4.,D0		; D0 <-- i	MOVE.32	#{A6}+PENTEY,A0	MOVE.32	{A6}+T4,{A0}+{D0}; PENTEY[i] <-- T4	SUB.32	#4.,D0		; D0 <-- i=i-1	COMP.32	#0,D0	JUMP,GE	1$	RET	;-------\; CALCAK >	calcul des coef. d'ordre 3 du polynme AKX[i] te AKY[i];-------/;;;in : rien;out: rien;mod: FCALCAK:	MOVE.32	#0,D0		; D0 <-- i=01$:	MOVE.32	#{A6}+PX,A0	MOVE.32	{A0}+{D0},{A6}+T1; T1 <-- PX[i]	ADD.32	#4.,D0		; D0 <-- i=i+1	MOVE.32	{A0}+{D0},{A6}+T2; T2 <-- PX[i+1]	MOVE.32 #{A6}+PARAM2,A0	MOVE.32	{A0}+{D0},{A6}+T3; T3 <-- PARAM2[i+1] non format	MOVE.32	#{A6}+PARAM,A0	MOVE.32	{A0}+{D0},{A6}+T4; T4 <-- PARAM[i+1]	MOVE.32	#{A6}+PENTEX,A0	MOVE.32	{A0}+{D0},{A6}+T5; T5 <-- PENTEX[i+1]	SUB.32	#4.,D0		; D0 <-- i	MOVE.32	{A0}+{D0},{A6}+T6; T6 <-- PENTEX[i]	CALL	DETAK		; retourne AKX[i]	MOVE.32	#{A6}+AKX,A0	MOVE.32	{A6}+T7,{A0}+{D0}; AKX[i] <-- T7	MOVE.32	#{A6}+PY,A0	MOVE.32	{A0}+{D0},{A6}+T1; T1 <-- PY[i]	ADD.32	#4.,D0		; D0 <-- i=i+1	MOVE.32	{A0}+{D0},{A6}+T2; T2 <-- PY[i+1]	MOVE.32	#{A6}+PENTEY,A0	MOVE.32	{A0}+{D0},{A6}+T5; T5 <-- PENTEY[i+1]	SUB.32	#4.,D0		; D0 <-- i	MOVE.32	{A0}+{D0},{A6}+T6; T6 <-- PENTEY[i]	CALL	DETAK		; retourne AKY[i]	MOVE.32	#{A6}+AKY,A0	MOVE.32	{A6}+T7,{A0}+{D0}; AKY[i] <-- T7	ADD.32	#4.,D0		; D0 <-- i=i+1	MOVE.32	{A6}+NBPOINTS,D5	SUB.32	#4,D5	COMP.32	D5,D0	JUMP,LT	1$	RET;-------\; CALCBK >	calcul des coef. d'ordre 3 du polynme BKX[i] te BKY[i];-------/;;;in : rien;out: rien;mod: FCALCBK:	MOVE.32	#0,D0		; D0 <-- i=01$:	MOVE.32	#{A6}+PX,A0	MOVE.32	{A0}+{D0},{A6}+T1; T1 <-- PX[i]	ADD.32	#4.,D0		; D0 <-- i=i+1	MOVE.32	{A0}+{D0},{A6}+T2; T2 <-- PX[i+1]	MOVE.32 #{A6}+PARAM2,A0	MOVE.32	{A0}+{D0},{A6}+T3; T3 <-- PARAM2[i+1] non format	MOVE.32	#{A6}+PARAM,A0	MOVE.32	{A0}+{D0},{A6}+T4; T4 <-- PARAM[i+1]	MOVE.32	#{A6}+PENTEX,A0	MOVE.32	{A0}+{D0},{A6}+T5; T5 <-- PENTEX[i+1]	SUB.32	#4.,D0		; D0 <-- i	MOVE.32	{A0}+{D0},{A6}+T6; T6 <-- PENTEX[i]	CALL	DETBK		; retourne BKX[i]	MOVE.32	#{A6}+BKX,A0	MOVE.32	{A6}+T7,{A0}+{D0}; BKX[i] <-- T7	MOVE.32	#{A6}+PY,A0	MOVE.32	{A0}+{D0},{A6}+T1; T1 <-- PY[i]	ADD.32	#4.,D0		; D0 <-- i=i+1	MOVE.32	{A0}+{D0},{A6}+T2; T2 <-- PY[i+1]	MOVE.32	#{A6}+PENTEY,A0	MOVE.32	{A0}+{D0},{A6}+T5; T5 <-- PENTEY[i+1]	SUB.32	#4.,D0		; D0 <-- i	MOVE.32	{A0}+{D0},{A6}+T6; T6 <-- PENTEY[i]	CALL	DETBK		; retourne BKY[i]	MOVE.32	#{A6}+BKY,A0	MOVE.32	{A6}+T7,{A0}+{D0}; BKY[i] <-- T7	ADD.32	#4.,D0		; D0 <-- i=i+1	MOVE.32	{A6}+NBPOINTS,D5	SUB.32	#4,D5	COMP.32	D5,D0	JUMP,LT	1$	RET;-------\; CALCPT >	calcul des points d'interpolation;-------/;;;in : rien;out: rien;mod: FCALCPT:	MOVE.32	#0,D0		; D0 <-- i=01$:	ADD.32	#4.,D0		; D0 <-- i=i+1	MOVE.32	#{A6}+PARAM,A2	MOVE.32	{A2}+{D0},D1	; D1 <-- PARAM[i+1]  (16|16)	CLR.32	D5	MOVE.32	D1,D3	SR.32	#8,D3	SR.32	#7,D3		; D3 <--2 * PARAM[i+1]  (32|0)	MOVE.32	D3,{A6}+TAMPO	; TAMPO <-- nbre de points de calcul	MOVE.32	D1,D4	CALL	DIV64		; D4 en (16|16)	MOVE.32	D4,{A6}+T1	; T1 <-- val. du pas = val. du paramtre t	SUB.32	#4.,D0		; D0 <-- i	MOVE.32	#{A6}+PX,A2	MOVE.32	{A2}+{D0},{A6}+PTX; PTX <-- PX[i]  (32|0)	MOVE.32	{A2}+{D0},D1	; D1 <-- PX[i]	SL.32	#8,D1		; (24|8)	SL.32	#8,D1		; (16|16)	SL.32	#4,D1		; (12|20)	MOVE.32	D1,{A6}+COPIX	; COPIX <-- PX[i]  (12|20)	MOVE.32	#{A6}+PY,A2	MOVE.32 {A2}+{D0},{A6}+PTY; PTY <-- PY[i]  (32|0)	MOVE.32	{A2}+{D0},D1	; D1 <-- PY[i]	SL.32	#8,D1		; (24|8)	SL.32	#8,D1		; (16|16)	SL.32	#4,D1		; (12|20)	MOVE.32	D1,{A6}+COPIY	; COPIY <-- PY[i]  (12|20)	CALL	METBUF		; met PTX et PTY dans le buffer	MOVE.32	D0,{A6}+TAMP	CALL	ININC		; initialise DX1,DX2,DX3,DY1,DY2 et DY3	CLR.32	D2		; initialise le compteur de boucle10$:	MOVE.32	{A6}+DX1,{A6}+T1; T1 <-- DX1	MOVE.32	{A6}+DX2,{A6}+T2; T2 <-- DX2	MOVE.32	{A6}+DX3,{A6}+T3; T3 <-- DX3	MOVE.32	{A6}+COPIX,{A6}+T0; T0 <-- COPIX	CALL	DETPT1		; retourne PTX et met  jour DX1 et DX2	MOVE.32	{A6}+T0,{A6}+COPIX	MOVE.32	{A6}+T5,{A6}+PTX	MOVE.32	{A6}+T1,{A6}+DX1	MOVE.32	{A6}+T2,{A6}+DX2	MOVE.32	{A6}+DY1,{A6}+T1; T1 <-- DY1	MOVE.32	{A6}+DY2,{A6}+T2; T2 <-- DY2	MOVE.32	{A6}+DY3,{A6}+T3; T3 <-- DY3	MOVE.32	{A6}+COPIY,{A6}+T0; T0 <-- COPIY	CALL	DETPT1		; retourne PTY et met  jour DY1 et DY2	MOVE.32	{A6}+T0,{A6}+COPIY	MOVE.32	{A6}+T5,{A6}+PTY	MOVE.32	{A6}+T1,{A6}+DY1	MOVE.32	{A6}+T2,{A6}+DY2	CALL	METBUF		; met PTX et PTY dans le buffer	INC.32	D2		; incrmente le compteur de boucle	COMP.32	{A6}+TAMPO,D2	JUMP,LE	10$	ADD.32	#4.,D0		; D0 <-- i=i+1	MOVE.32	{A6}+NBPOINTS,D3; nombre de points donns	SUB.32	#4.,D3		; nombre de segments	COMP.32	D3,D0	JUMP,LT	1$	RET;-------\; EFFRAC > 	prend la racine de tous les paramtres;-------/;;;in : rien;out: rien;mod: FEFFRAC:	MOVE.32	#4.,D0		; D0 <-- i=11$:	MOVE.32	#{A6}+PARAM2,A0	MOVE.32	{A0}+{D0},{A6}+TAMPON ; TAMPON <-- PARAM2[i]	CALL	RACINE		; racine carre du paramtre	MOVE.32	#{A6}+PARAM,A0	MOVE.32	{A6}+TAMP,{A0}+{D0}   ; PARAM[i] <-- TAMP	ADD.32	#4.,D0		; D0 <-- i=i+1	COMP.32	{A6}+NBPOINTS,D0	JUMP,LT	1$	RET;------\; INCYC >	calcul CO1,CO2[i] et CO3[i];------/;;;in : rien;out: rien;mod: FINCYC:	MOVE.32	#0,D0		; D0 <-- i=0	MOVE.32	#{A6}+PX,A0	MOVE.32	{A0}+{D0},{A6}+T1; T1 <-- PX[0]	ADD.32	#4.,D0		; D0 <-- i=1	MOVE.32	{A0}+{D0},{A6}+T2; T2 <-- PX[1]	MOVE.32	#{A6}+PARAM,A0	MOVE.32	{A0}+{D0},{A6}+T6; T6 <-- PARAM[1]	MOVE.32	{A6}+NBPOINTS,D0	SUB.32	#4.,D0		; D0 <-- i=n	MOVE.32	{A0}+{D0},{A6}+T5; T5 <-- PARAM[n]	MOVE.32	#{A6}+PX,A0	MOVE.32	{A0}+{D0},{A6}+T4; T4 <-- PX[n]	SUB.32	#4.,D0		; D0 <-- i=n-1	MOVE.32	{A0}+{D0},{A6}+T3; T3 <-- PX[n-1]	CALL	DETCO1		; retourne CO1X	MOVE.32	{A6}+T7,{A6}+CO1X	MOVE.32	#0,D0		; D0 <-- i=0	MOVE.32	#{A6}+PY,A0	MOVE.32	{A0}+{D0},{A6}+T1; T1 <-- PY[0]	ADD.32	#4.,D0		; D0 <-- i=1	MOVE.32	{A0}+{D0},{A6}+T2; T2 <-- PY[1]	MOVE.32	{A6}+NBPOINTS,D0	SUB.32	#4.,D0		; D0 <-- i=n	MOVE.32	#{A6}+PY,A0	MOVE.32	{A0}+{D0},{A6}+T4; T4 <-- PY[n]	SUB.32	#4.,D0		; D0 <-- i=n-1	MOVE.32	{A0}+{D0},{A6}+T3; T3 <-- PY[n-1]	CALL	DETCO1		; retourne CO1Y	MOVE.32	{A6}+T7,{A6}+CO1Y	MOVE.32	#4.,D0		; D0 <-- i=110$:	MOVE.32	#{A6}+PARAM,A0	MOVE.32	{A0}+{D0},{A6}+T1; T1 <-- PARAM[i]	ADD.32	#4.,D0		; D0 <-- i=i+1	MOVE.32	{A0}+{D0},{A6}+T2; T2 <-- PARAM[i+1]	MOVE.32	#{A6}+PX,A0	MOVE.32	{A0}+{D0},{A6}+T4; T4 <-- PX[i+1]	SUB.32	#4.,D0		; D0 <-- i	MOVE.32	{A0}+{D0},{A6}+T3; T3 <-- PX[i]	SUB.32	#4.,D0		; D0 <-- i=i-1	MOVE.32	{A0}+{D0},{A6}+T5; T5 <-- PX[i-1]	CALL	DETCO2		; retourne CO2X[i]	ADD.32	#4.,D0		; D0 <-- i	MOVE.32	#{A6}+CO2X,A0	MOVE.32	{A6}+T6,{A0}+{D0}; CO2X[i] <-- T6	MOVE.32	#{A6}+PY,A0	MOVE.32	{A0}+{D0},{A6}+T3; T3 <-- PY[i]	ADD.32	#4.,D0		; D0 <-- i=i+1	MOVE.32 {A0}+{D0},{A6}+T4; T4 <-- PY[i+1]	SUB.32	#8.,D0		; D0 <-- i=i-1	MOVE.32	{A0}+{D0},{A6}+T5; T5 <-- PY[i-1]	CALL	DETCO2		; retourne CO2Y[i]	ADD.32	#4.,D0		; D0 <-- i	MOVE.32	#{A6}+CO2Y,A0	MOVE.32	{A6}+T6,{A0}+{D0}; CO2Y[i] <-- T6	CALL	DETCO3		; retourne CO3[i]	MOVE.32	#{A6}+CO3,A0	MOVE.32	{A6}+T3,{A0}+{D0}; CO3[i] <-- T3	ADD.32	#4.,D0		; D0 <-- i=i+1	MOVE.32	{A6}+NBPOINTS,D5; nombre de points	SUB.32	#4.,D5		; nombre de segment	COMP.32	D5,D0	JUMP,LT	10$	RET;------\; CALCK >	calcul des coef. K1X[n-1],K1Y[n-1],K2[n-1];------/;;;in : rien;out: rien;mod: FCALCK:	MOVE.32	{A6}+NBPOINTS,D0	SUB.32	#8.,D0		; D0 <-- i=n-1	MOVE.32	#{A6}+CO2X,A0	MOVE.32	{A0}+{D0},D4	; D4 <-- CO2X[n-1]	MOVE.32	D4,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; CO2[n-1] positif ?	JUMP,EQ	10$	NEG.32	D410$:	MOVE.32	#65536.,D3	CALL	MUL64		; formatage pour la division	MOVE.32	#{A6}+CO3,A0	MOVE.32	{A0}+{D0},D3	; D3 <-- CO3[n-1]	CALL	DIV64		; D4 <-- CO2X[n-1] / CO3[n-1]	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	20$	NEG.32	D420$:	MOVE.32	#{A6}+K1X,A0	MOVE.32	D4,{A0}+{D0}	; K1X[n-1] <-- D4  (16|16)	MOVE.32	#{A6}+CO2Y,A0	MOVE.32	{A0}+{D0},D4	; D4 <-- CO2Y[n-1]	MOVE.32	D4,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; CO2[n-1] positif ?	JUMP,EQ	30$	NEG.32	D430$:	MOVE.32	#65536.,D3	CALL	MUL64		; formatage pour la division	MOVE.32	#{A6}+CO3,A0	MOVE.32	{A0}+{D0},D3	; D3 <-- CO3[n-1]	CALL	DIV64		; D4 <-- CO2Y[n-1] / CO3[n-1]	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	40$	NEG.32	D440$:	MOVE.32	#{A6}+K1Y,A0	MOVE.32	D4,{A0}+{D0}	; K1Y[n-1] <-- D4  (16|16)	MOVE.32	#{A6}+PARAM,A0	MOVE.32	{A0}+{D0},D4	; D4 <-- PARAM[n-1]  (16|16)	MOVE.32	#65536.,D3	CALL	MUL64		; formatage pour la division	MOVE.32	#{A6}+CO3,A0	MOVE.32	{A0}+{D0},D3	; D3 <-- CO3[n-1]	CALL	DIV64		; D4 <-- PARAM[n-1] / CO3[n-1]	NEG.32	D4		; D4 <-- -(PARAM[n-1] / PARAM[n])	MOVE.32	#{A6}+K2,A0	MOVE.32	D4,{A0}+{D0}	; K2[n-1] <-- D4  (16|16)	RET;-------\; CALCKS >	calcul les K1X[i],K1Y[i],K2[i],K3[i],CK1[i] et CK2[i];-------/;;;in : rien;out: rien;mod: FCALCKS:	MOVE.32	{A6}+NBPOINTS,D0	SUB.32	#8.,D0		; D0 <-- i=n-1	MOVE.32	#{A6}+K2,A0	MOVE.32	{A0}+{D0},D1	; D1 <-- K2[n-1]	SUB.32	#4.,D0		; D0 <-- i=n-2	MOVE.32	#{A6}+CK1,A0	MOVE.32	D1,{A0}+{D0}	; CK1[n-2] <-- K2[n-1]	MOVE.32	{A6}+CO1X,D3	; D3 <-- CO1X	ADD.32	#4.,D0		; D0 <-- i=n-1	MOVE.32	#{A6}+K1X,A0	SUB.32	{A0}+{D0},D3	; D3 <-- CO1X - K1X[n-1]	SUB.32	#4.,D0		; D0 <-- i=n-2	MOVE.32	#{A6}+CK2X,A0	MOVE.32	D3,{A0}+{D0}	; CK2X[n-2] <-- CO1X - K1X[n-1]	MOVE.32	{A6}+CO1Y,D3	; D3 <-- CO1Y	ADD.32	#4.,D0		; D0 <-- i=n-1	MOVE.32	#{A6}+K1Y,A0	SUB.32	{A0}+{D0},D3	; D3 <-- CO1Y - K1Y[n-1]	SUB.32	#4.,D0		; D0 <-- i=n-2	MOVE.32	#{A6}+CK2Y,A0	MOVE.32	D3,{A0}+{D0}	; CK2Y[n-2] <-- CO1Y - K1Y[n-1]	COMP.32	#4,D0		; avant dernier point ?	JUMP,EQ	20$10$:	MOVE.32	#{A6}+CO3,A0	MOVE.32	{A0}+{D0},{A6}+T1; T1 <-- CO3[i]	MOVE.32	#{A6}+PARAM,A0	MOVE.32	{A0}+{D0},{A6}+T2; T2 <-- PARAM[i]	ADD.32	#4.,D0		; D0 <-- i=i+1	MOVE.32	#{A6}+K2,A0	MOVE.32	{A0}+{D0},{A6}+T3; T3 <-- K2[i+1]	CALL	DETK3		; retourne K3[i]	SUB.32	#4.,D0		; D0 <-- i	MOVE.32	#{A6}+K3,A0	MOVE.32	{A6}+T7,{A0}+{D0}; K3[i] <-- T7	MOVE.32	{A6}+T2,D3	; D3 <-- PARAM[i]	MOVE.32	#65536.,D4	CLR.32	D5	CALL	MUL64		; formatage pour la division	MOVE.32	{A6}+T7,D3	; D3 <-- K3[i]	CALL	DIV64		; D4 <-- PARAM[i] / K3[i]	NEG.32	D4		; D4 <-- - (PARAM[i] / K3[i])	MOVE.32	#{A6}+K2,A0	MOVE.32	D4,{A0}+{D0}	; K2[i] <-- D4	MOVE.32	#{A6}+CO2X,A0	MOVE.32	{A0}+{D0},{A6}+T4; T4 <-- CO2X[i]	ADD.32	#4.,D0		; D0 <-- i=i+1	MOVE.32	#{A6}+K1X,A0	MOVE.32	{A0}+{D0},{A6}+T5; T5 <-- K1X[i+1]	CALL	DETK1		; retourne K1X[i]	SUB.32	#4.,D0		; D0 <-- i	MOVE.32	{A6}+T6,{A0}+{D0}; K1X[i] <-- T6	MOVE.32	#{A6}+CO2Y,A0	MOVE.32	{A0}+{D0},{A6}+T4; T4 <-- CO2Y[i]	ADD.32	#4.,D0		; D0 <-- i=i+1	MOVE.32	#{A6}+K1Y,A0	MOVE.32	{A0}+{D0},{A6}+T5; T5 <-- K1Y[i+1]	CALL	DETK1		; retourne K1Y[i]	SUB.32	#4.,D0		; D0 <-- i	MOVE.32	{A6}+T6,{A0}+{D0}; K1Y[i] <-- T6	SUB.32	#4.,D0		; D0 <-- nouvel i=i-1	COMP.32	#4.,D0		; avant dernier point ?	JUMP,EQ	20$	ADD.32	#4.,D0		; D0 <-- i=i+1	MOVE.32	#{A6}+K2,A0	MOVE.32	{A0}+{D0},{A6}+T2; T2 <-- K2[i+1]	MOVE.32	#{A6}+CK1,A0	MOVE.32	{A0}+{D0},{A6}+T1; T1 <-- CK1[i+1]	CALL	DETCK1		; retourne CK1[i]	SUB.32	#4.,D0		; D0 <-- i	MOVE.32	{A6}+T3,{A0}+{D0}; CK1[i] <-- T3	ADD.32	#4.,D0		; D0 <-- i=i+1	MOVE.32	#{A6}+K1X,A0	MOVE.32	{A0}+{D0},{A6}+T4; T4 <-- K1X[i+1]	MOVE.32	#{A6}+CK2X,A0	MOVE.32	{A0}+{D0},{A6}+T5; T5 <-- CK2X[i+1]	CALL	DETCK2		; retourne CK2X[i]	SUB.32	#4.,D0		; D0 <-- i	MOVE.32	{A6}+T5,{A0}+{D0}; CK2X[i] <-- T5	ADD.32	#4.,D0		; D0 <-- i=i+1	MOVE.32	#{A6}+K1Y,A0	MOVE.32	{A0}+{D0},{A6}+T4; T4 <-- K1Y[i+1]	MOVE.32	#{A6}+CK2Y,A0	MOVE.32	{A0}+{D0},{A6}+T5; T5 <-- CK2Y[i+1]	CALL	DETCK2		; retourne CK2Y[i]	SUB.32	#4.,D0		; D0 <-- i	MOVE.32	{A6}+T5,{A0}+{D0}; CK2Y[i] <-- T5	JUMP	10$20$:	CALL	DETCYT	RET;-------\; DETCYT >	calcul les coeff. pour les 2 premiers points;......./;;;in : rien;out: rien;mod: FDETCYT:	MOVE.32	#4.,D0		; D0 <-- i=1	MOVE.32	#{A6}+CO3,A0	MOVE.32	{A0}+{D0},{A6}+T1; T1 <-- CO3[1]	MOVE.32	#{A6}+PARAM,A0	MOVE.32	{A0}+{D0},{A6}+T2; T2 <-- PARAM[1]	ADD.32	#4.,D0		; D0 <-- i=2	MOVE.32	#{A6}+K2,A0	MOVE.32	{A0}+{D0},{A6}+T3; T3 <-- K2[2]	CALL	DETK3		; retourne K3[1]	SUB.32	#4.,D0		; D0 <-- 1	MOVE.32	#{A6}+K3,A0	MOVE.32	{A6}+T7,{A0}+{D0}; K3[1] <-- T7	MOVE.32	{A6}+T2,D3	; D3 <-- PARAM[1]	MOVE.32	#65536.,D4	CLR.32	D5	CALL	MUL64		; formatage pour la division	MOVE.32	{A6}+T7,D3	; D3 <-- K3[1]	CALL	DIV64		; D4 <-- PARAM[i] / K3[1]	NEG.32	D4		; D4 <-- - (PARAM[i] / K3[1])	MOVE.32	#{A6}+K2,A0	MOVE.32	D4,{A0}+{D0}	; K2[1] <-- D4	MOVE.32	#{A6}+CO2X,A0	MOVE.32	{A0}+{D0},{A6}+T4; T4 <-- CO2X[1]	ADD.32	#4.,D0		; D0 <-- i=2	MOVE.32	#{A6}+K1X,A0	MOVE.32	{A0}+{D0},{A6}+T5; T5 <-- K1X[2]	CALL	DETK1		; retourne K1X[1]	SUB.32	#4.,D0		; D0 <-- 1	MOVE.32	{A6}+T6,{A0}+{D0}; K1X[1] <-- T6	MOVE.32	#{A6}+CO2Y,A0	MOVE.32	{A0}+{D0},{A6}+T4; T4 <-- CO2Y[1]	ADD.32	#4.,D0		; D0 <-- i=2	MOVE.32	#{A6}+K1Y,A0	MOVE.32	{A0}+{D0},{A6}+T5; T5 <-- K1Y[2]	CALL	DETK1		; retourne K1Y[1]	SUB.32	#4.,D0		; D0 <-- 1	MOVE.32	{A6}+T6,{A0}+{D0}; K1Y[1] <-- T6	ADD.32	#4.,D0		; D0 <-- i=2	MOVE.32	#{A6}+K2,A0	MOVE.32	{A0}+{D0},{A6}+T2; T2 <-- K2[2]	MOVE.32	#{A6}+CK1,A0	MOVE.32	{A0}+{D0},{A6}+T1; T1 <-- CK1[2]	CALL	DETCK1		; retourne une partie de CK1[1]	CALL	DETRAP		; retourne PARAM[n] / PARAM[1]	MOVE.32	{A6}+T7,D1	; D1 <-- PARAM[n] / PARAM[1]	ADD.32	{A6}+T3,D1	; D1 = rsultat	SUB.32	#4.,D0		; D0 <-- i	MOVE.32	D1,{A0}+{D0}	; CK1[i] <-- T3	ADD.32	#4.,D0		; D0 <-- i=2	MOVE.32	#{A6}+K1X,A0	MOVE.32	{A0}+{D0},{A6}+T4; T4 <-- K1X[2]	MOVE.32	#{A6}+CK2X,A0	MOVE.32	{A0}+{D0},{A6}+T5; T5 <-- CK2X[2]	CALL	DETCK2		; retourne CK2X[1]	SUB.32	#4.,D0		; D0 <-- 1	MOVE.32	{A6}+T5,{A0}+{D0}; CK2X[1] <-- T5	ADD.32	#4.,D0		; D0 <-- i=2	MOVE.32	#{A6}+K1Y,A0	MOVE.32	{A0}+{D0},{A6}+T4; T4 <-- K1Y[2]	MOVE.32	#{A6}+CK2Y,A0	MOVE.32	{A0}+{D0},{A6}+T5; T5 <-- CK2Y[2]	CALL	DETCK2		; retourne CK2Y[1]	SUB.32	#4.,D0		; D0 <-- 1	MOVE.32	{A6}+T5,{A0}+{D0}; CK2Y[i] <-- T5	MOVE.32	#{A6}+K2,A0	MOVE.32	{A0}+{D0},{A6}+T2; T2 <-- K2[1]	MOVE.32	#{A6}+CK1,A0	MOVE.32	{A0}+{D0},{A6}+T1; T1 <-- CK1[1]	CALL	DETCK1		; retourne une partie de CK1[0]	CALL	DETRAP		; retourne PARAM{n] / PARAM[1]	MOVE.32	{A6}+T7,D1	; D1 <-- PARAM[n] / PARAM[1]	ADD.32	#H'10000,D1	; D1 <-- (PARAM[n] / PARAM[1]) + 1 (16|16)	SL.32	#1,D1		; D1 <-- 2 * {(PARAM[n] / PARAM[1]) + 1 }	ADD.32	D1,{A6}+T3	; T3 = rsultat	SUB.32	#4.,D0		; D0 <-- 0	MOVE.32	{A6}+T3,{A0}+{D0}; CK1[0] <-- T3	ADD.32	#4.,D0		; D0 <-- i=1	MOVE.32	#{A6}+K1X,A0	MOVE.32	{A0}+{D0},{A6}+T4; T4 <-- K1X[1]	MOVE.32	#{A6}+CK2X,A0	MOVE.32	{A0}+{D0},{A6}+T5; T5 <-- CK2X[1]	CALL	DETCK2		; retourne CK2X[0]	SUB.32	#4.,D0		; D0 <-- 0	MOVE.32	{A6}+T5,{A0}+{D0}; CK2X[0] <-- T5	ADD.32	#4.,D0		; D0 <-- i=1	MOVE.32	#{A6}+K1Y,A0	MOVE.32	{A0}+{D0},{A6}+T4; T4 <-- K1Y[1]	MOVE.32	#{A6}+CK2Y,A0	MOVE.32	{A0}+{D0},{A6}+T5; T5 <-- CK2Y[1]	CALL	DETCK2		; retourne CK2Y[0]	SUB.32	#4.,D0		; D0 <-- 0	MOVE.32	{A6}+T5,{A0}+{D0}; CK2Y[0] <-- T5	RET;--------\; PENTEIC >	calcul PENTE[0] et PENTE[n] , condition cyclique;--------/;;;in : rien;out: rien;mod: FPENTEIC:	MOVE.32	#0,{A6}+TAMP	; initialise le testeur de signe	MOVE.32	#0,D0		; D0 <-- i=0	MOVE.32	#{A6}+CK2X,A0	MOVE.32	{A0}+{D0},D3	; D3 <-- CK2X[0]	MOVE.32	D3,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; CK2X[0] positif ?	JUMP,EQ	10$	NEG.32	D3	MOVE.32	#1,{A6}+TAMP	; => CK2X[0] ngatif10$:	MOVE.32	#{A6}+CK1,A0	MOVE.32	{A0}+{D0},D6	; D6 <-- CK1[0]	MOVE.32	D6,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; CK1[0] positif ?	JUMP,EQ	30$	NEG.32	D6	COMP.32	#0,{A6}+TAMP	JUMP,EQ	20$	MOVE.32	#0,{A6}+TAMP	; CK2X[0] ng. et CK1[0] ng.	JUMP	30$20$:	MOVE.32	#1,{A6}+TAMP	; CK2X[0] pos. et CK1[0] ng.30$:	MOVE.32	#65536.,D4	CLR.32	D5	CALL	MUL64		; formatage pour la division	MOVE.32	D6,D3	CALL	DIV64		; D4 <-- CK2X[0] / CK1[0]  (16|16)	COMP.32	#0,{A6}+TAMP	JUMP,EQ	40$	NEG.32	D440$:	MOVE.32	#{A6}+PENTEX,A0	MOVE.32	D4,{A0}+{D0}	; PENTEX[0] <-- D4	MOVE.32	{A6}+NBPOINTS,D0	SUB.32	#4.,D0		; se positionne au dernier point	MOVE.32	D4,{A0}+{D0}	; PENTEX[n] <-- D4	MOVE.32	#0,{A6}+TAMP	; initialise le testeur de signe	MOVE.32	#0,D0		; D0 <-- i=0	MOVE.32	#{A6}+CK2Y,A0	MOVE.32	{A0}+{D0},D3	; D3 <-- CK2Y[0]	MOVE.32	D3,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; CK2Y[0] positif ?	JUMP,EQ	50$	NEG.32	D3	MOVE.32	#1,{A6}+TAMP	; => CK2Y[0] ngatif50$:	MOVE.32	#{A6}+CK1,A0	MOVE.32	{A0}+{D0},D6	; D6 <-- CK1[0]	MOVE.32	D6,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; CK1[0] positif ?	JUMP,EQ	70$	NEG.32	D6	COMP.32	#0,{A6}+TAMP	JUMP,EQ	60$	MOVE.32	#0,{A6}+TAMP	; CK2Y[0] ng. et CK1[0] ng.	JUMP	70$60$:	MOVE.32	#1,{A6}+TAMP	; CK2Y[0] pos. et CK1[0] ng.70$:	MOVE.32	#65536.,D4	CLR.32	D5	CALL	MUL64		; formatage pour la division	MOVE.32	D6,D3	CALL	DIV64		; D4 <-- CK2Y[0] / CK1[0]  (16|16)	COMP.32	#0,{A6}+TAMP	JUMP,EQ	80$	NEG.32	D480$:	MOVE.32	#{A6}+PENTEY,A0	MOVE.32	D4,{A0}+{D0}	; PENTEY[0] <-- D4	MOVE.32	{A6}+NBPOINTS,D0	SUB.32	#4.,D0		; se positionne au dernier point	MOVE.32	D4,{A0}+{D0}	; PENTEX[n] <-- D4	RET;--------\; PENTENC >	calcul PENTEX[i] et PENTEY[i] , condition cyclique;--------/;;;in : rien;out: rien;mod:FPENTENC:	MOVE.32	#0,D0		; D0 <-- i=01$:	MOVE.32	#{A6}+PENTEX,A0	MOVE.32	{A0}+{D0},{A6}+T1; T1 <-- PENTEX[i]	ADD.32	#4.,D0		; D0 <-- i=i+1	MOVE.32	#{A6}+K2,A0	MOVE.32	{A0}+{D0},{A6}+T2; T2 <-- K2[i+1]	MOVE.32	#{A6}+K1X,A0	MOVE.32	{A0}+{D0},{A6}+T3; T3 <-- K1X[i+1]	CALL	DETPENTC	; retourne PENTEX[i+1]	MOVE.32	#{A6}+PENTEX,A0	MOVE.32	{A6}+T1,{A0}+{D0}; PENTEX[i+1] <-- T1	SUB.32	#4.,D0		; D0 <-- i	MOVE.32	#{A6}+PENTEY,A0	MOVE.32	{A0}+{D0},{A6}+T1; T1 <-- PENTEY[i]	ADD.32	#4.,D0		; D0 <-- i=i+1	MOVE.32	#{A6}+K2,A0	MOVE.32	{A0}+{D0},{A6}+T2; T2 <-- K2[i+1]	MOVE.32	#{A6}+K1Y,A0	MOVE.32	{A0}+{D0},{A6}+T3; T3 <-- K1Y[i+1]	CALL	DETPENTC	; retourne PENTEY[i+1]	MOVE.32	#{A6}+PENTEY,A0	MOVE.32	{A6}+T1,{A0}+{D0}; PENTEY[i+1] <-- T1	MOVE.32	{A6}+NBPOINTS,D6	SUB.32	#8.,D6		; position n-2	COMP.32	D6,D0	JUMP,LT	1$	RET;.....................................................;; Routines de bas niveau; ----------------------;--------\; METBUF  >	affiche les points et vide le buffer;......../;;in : rien;out: rien;mod: FMETBUF:	PUSHM.32 D3|A3	MOVE.32	#{A6}+BUFFER+1,A3		MOVE.8	#DRAWDOT,{A3}+0		;affiche un point	MOVE.16	{A6}+PTX+2,{A3}+1	;le X	MOVE.16	{A6}+PTY+2,{A3}+3	;le Y	MOVE.8	#INVDOT,{A3}+5		;le mode	MOVE.16	#6,D3	.16	LIB,?STRING	POPM.32	D3|A3	RET;------\; DETPT >	effectue p(t) = a * t**3 + b * t**2 + c * t + d;------/;;;in : rien;out: rien;mod: FDETPT:	PUSHM.32 D0|D1|D2|D3|D4	MOVE.32	{A6}+T1,D1	; D1 <-- valeur du paramtre t		MOVE.32	{A6}+T2,D3	; D3 <-- AKX[i] ou AKY[i]	MOVE.32	D3,{A6}+TAMPON	CALL	TSIGNE 	COMP.32	#0,{A6}+SIGNE	; AK[i] positif ?	JUMP,EQ	15$	NEG.32	D315$:	MOVE.32	D1,D4		; D4 <-- paramtre	CLR.32	D5	CALL	MUL64		; D5D4 <-- a * t  ( * 2**48)	MOVE.32	#65536.,D3	CALL	DIV64		; ( * 2**32)	SR.32	#8,D4		; format (8|24)	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	20$	NEG.32	D420$:	MOVE.32	{A6}+T3,D3	; D3 <-- BKX[i] ou BKY[i] (32|0)	MOVE.32	D3,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; BK[i] positif ?	JUMP,EQ	21$	ASR.32	#8,D3		; formatage pour 24 bits fractionnaires	JUMP	25$21$:	SR.32	#8,D3		; formatage pour 24 bits fractionnaires25$:	ADD.32	D3,D4		; D4 <-- (b + a * t)    (8|24)	MOVE.32	D4,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	27$	NEG.32	D427$:	MOVE.32	D1,D3		; D3 <-- PARAM[i]	CLR.32	D5	CALL	MUL64		; ( * 2**40)	MOVE.32	#65536.,D3	; divise par 2**16	CALL	DIV64		; D4 <-- t *(b + a * t)  ( * 2**24)	SR.32	#4,D4		; D4 en (12|20)	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	30$	NEG.32	D430$:	MOVE.32	{A6}+T4,D3	; D3 <-- PENTEX[i] ou PENTEY[i]  (16|16)	SL.32	#4,D3		; (12|20)	ADD.32	D3,D4		; D4 <-- c + t *(b + a * t)	MOVE.32	D4,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; D4 positif ?	JUMP,EQ	35$	NEG.32	D435$:	MOVE.32 D1,D3		; D3 <--PARAM[i]  (16|16)	CLR.32	D5	CALL	MUL64		; ( * 2**36)	MOVE.32	#65536.,D3	CALL	DIV64		; D4 <-- t *( c + t *(b + t * a))  ( * 2**20)	TEST.32	D4:#19		; teste si le bit 19 est  1	JUMP,EQ	40$	SR.32	#8,D4	SR.32	#8,D4	SR.32	#4,D4		; (32|0)	INC.32	D4		; arrondi  la valeur suprieure	JUMP	45$40$:	SR.32	#8,D4	SR.32	#8,D4	SR.32	#4,D445$:	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	50$	NEG.32	D450$:	ADD.32	{A6}+T5,D4	; D4 <-- d + t *(c + t *(b + t * a))	MOVE.32	D4,{A6}+T6	POPM.32	D0|D1|D2|D3|D4	RET;--------\; DETPENT >	calcul les PENTEX[i] et PENTEY[i];......../;;;in : rien;out: rien;mod: FDETPENT:	MOVE.32	{A6}+T1,D1	; D1 <-- AX[i] ou AY[i]	MOVE.32	{A6}+T2,D3	; D3 <-- BX[i] ou BY[i]	MOVE.32	{A6}+T3,D4	; D4 <-- PENTEX[i+1] ou PENTEY[i+1]	MOVE.32	#0,{A6}+FANION	; initialise le fanion	MOVE.32	D3,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; BX[i] positif ?	JUMP,EQ	10$	NEG.32	D3	MOVE.32	#1,{A6}+FANION	; laisse une trace si BX[i] est ngatif10$:	MOVE.32	D4,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; PENTEX[i+1] positif ?	JUMP,EQ	20$	NEG.32	D4	COMP.32	#0,{A6}+FANION	JUMP,EQ	15$		; BX[i] > 0 et PENTEX[i+1] < 0	JUMP 20$		; BX[i] < 0 et PENTEX[i+1] < 015$:	MOVE.32	#1,{A6}+FANION20$:	CLR.32	D5	CALL	MUL64		; BX[i] * PENTEX[i+1] non signe	MOVE.32	#65536.,D3	CALL	DIV64		; formatage de BX[i] * PENTEX[i+1]	COMP.32	#0,{A6}+FANION	JUMP,EQ	25$	NEG.32	D425$:	SUB.32	D4,D1		; D1 <-- AX[i] - BX[i] * PENTEX[i+1]	MOVE.32	D1,{A6}+T4	RET;------\; DETAK >	dtermine les coefficients AKX[i] et AKY[i];....../;;;in : rien;out: rien;mod: FDETAK:	PUSHM.32 D1|D3|D4|D5|D6	MOVE.32	{A6}+T1,D5	; D5 <-- PX[i] ou PY[i]	SUB.32	{A6}+T2,D5	; D5 <-- PX[i] - PX[i+1] ou PY[i] - PY[i+1]				; non format	SL.32	#1,D5		; D5 <-- 2 * (P[i] - P[i+1]) non format	MOVE.32	{A6}+T3,D6	; D6 <-- PARAM2[i+1] non format	MOVE.32	D5,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; D5 positif ?	JUMP,EQ	10$	NEG.32	D510$:	CLR.32	D4	MOVE.32 D6,D3	CALL	DIV64		; D4 <-- 2 * (P[i] - P[i+1]) / PARAM2[i+1]				; format avec 32 bits pour les fractions	MOVE.32	#65536.,D3	CLR.32	D5	CALL	MUL64	MOVE.32	{A6}+T4,D3	; D3 <-- PARAM[i+1]	CALL	DIV64		; D4 <-- 2 * (P[i] - P[i+1]) / PARAM[i+1]**3	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	20$	NEG.32	D420$:	MOVE.32	D4,{A6}+TAMP	MOVE.32	{A6}+T5,D4	; D4 <-- PENTEX[i+1] ou PENTEY[i+1]	MOVE.32	D4,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; PENTEX[i+1] ou PENTEY[i] positif ?	JUMP,EQ	25$	NEG.32	D425$:	CLR.32	D5	MOVE.32	#65536.,D3	CALL	MUL64	MOVE.32	D6,D3		; D3 <-- PARAM2[i+1] non format	CALL	DIV64		; D1 <-- PENTE[i+1] / PARAM2[i+1] format	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	30$	NEG.32	D430$:	ADD.32	D4,{A6}+TAMP	MOVE.32	{A6}+T6,D4	; D4 <-- PENTEX[i] ou PENTEY[i]	MOVE.32	D4,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; PENTE[i] positif ?	JUMP,EQ	35$	NEG.32	D435$:	MOVE.32	#65536.,D3	CLR.32	D5	CALL	MUL64		; formatage pour 32 bits fractionnaires	MOVE.32	D6,D3	CALL	DIV64		; D1 <-- PENTEX[i] / PARAM2[i+1] format	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	40$	NEG.32	D440$:	ADD.32	{A6}+TAMP,D4	; D4 = AKX[i] ou AKY[i]	MOVE.32	D4,{A6}+T7	; T7 <-- AKX[i] ou AKY[i]	POPM.32	D1|D3|D4|D5|D6	RET;------\; DETBK >	calcul les coef. d'ordre 2 du polynme BKX[i] et BKY[i];------/;;;in : rien;out: rien;mod: FDETBK:	MOVE.32	{A6}+T3,D6	; D6 <-- PARAM2[i+1]  non format	MOVE.32	{A6}+T2,D5	; D5 <-- PX[i+1] ou PY[i+1]	SUB.32	{A6}+T1,D5	; D5 <-- PX[i+1] - PX[i] ou PY[i+1] - PY[i]	MUL.A16	#3.,D5		; D5 <-- 3 * (P[i+1] - P[i]) non format	MOVE.32	D5,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; D5 positif ?	JUMP,EQ	10$	NEG.32	D510$:	CLR.32	D4	MOVE.32	D6,D3	CALL	DIV64		; D4 <-- 3 * (P[i+1] - P[i]) / PARAM2[i+1]				; format sur 32 bits fractionnaires	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	15$	NEG.32	D415$:	MOVE.32	D4,{A6}+TAMP	MOVE.32	{A6}+T6,D5	; D5 <-- PENTEX[i] ou PENTEY[i]	SL.32	#1,D5		; D5 <-- 2 * PENTE[i]	MOVE.32	{A6}+T4,D6	; D6 <-- PARAM[i+1]	MOVE.32	D5,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; D5 positif ?	JUMP,EQ	20$	NEG.32	D520$:	CLR.32	D4	MOVE.32	D6,D3	CALL	DIV64		; D4 <-- (2 * PENTE[i]) / PARAM[i+1]				; format sur 32 bits pour les fractionnaires	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	25$	NEG.32	D425$:	SUB.32	D4,{A6}+TAMP	MOVE.32	{A6}+T5,D5	; D5 <-- PENTEX[i+1] ou PENTEY[i+1]	MOVE.32	D5,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; D5 positif ?	JUMP,EQ	30$	NEG.32	D530$:	CLR.32	D4	MOVE.32	D6,D3		; D3 <-- PARAM[i+1]	CALL	DIV64		; D4 <-- PENTE[i+1] / PARAM[i+1]				; format sur 32 bits pour les rfactionnaires	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	35$	NEG.32	D435$:	SUB.32	D4,{A6}+TAMP	; TAMP = BK[i]	MOVE.32	{A6}+TAMP,D4	MOVE.32	 D4,{A6}+T7	; T7 <-- BKX[i] ou BKY[i]	RET;-------\; DETPT1 >	retourne PTX ou PTY;......./;;;in : rien;out: rien;mod: FDETPT1:	PUSHM.32 D1|D2	MOVE.32	{A6}+T0,D1	; D1 <-- COPIX  ou COPIY (12|20)	ADD.32	{A6}+T1,D1	; D1 <-- COPIX + DX1 ou 				; COPIY + DY1  (12|20)	MOVE.32	D1,{A6}+T0	; T0 <-- nouveau COPIX ou COPIY	TEST.32	D1:#19		; teste si le bit 19 est  0	JUMP,EQ	10$	SR.32	#8,D1		; (20|12)	SR.32	#8,D1		; (28|4)	SR.32	#4,D1		; (32|0)	INC.32	D1	JUMP	15$10$:	SR.32	#8,D1		; (20|12)	SR.32	#8,D1		; (28|4)	SR.32	#4,D1		; (32|0)15$:	MOVE.32	D1,{A6}+T5	; T5 <-- nouveau PTX ou PTY	MOVE.32	{A6}+T2,D2	; D2 <-- DX2 ou DY2  (0|32)	MOVE.32	D2,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; DX2 ou DY2 positif ?	JUMP,EQ	20$	NEG.32	D220$:	SR.32	#8,D2		; (8|24)	SR.32	#4,D2		; (12|20)	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	25$	NEG.32	D225$:	ADD.32	D2,{A6}+T1	; D1 <-- D1 + D2	MOVE.32	{A6}+T3,D2	ADD.32	D2,{A6}+T2	; D2 <-- D2 + D3	POPM.32	D1|D2	RET;---\; BI >		calcul les coefficients intermdiaires BX[i] et BY[i];---/;;;in : rien;out: rien;mod : FBI:	MOVE.32	{A6}+T1,D1	; D1 <-- PARAM[i]	MOVE.32	{A6}+T2,D2	; D2 <-- PARAM[i+1]	ADD.32	D2,D1		; D1 <-- PARAM[i+1] + PARAM[i]	SL.32	#1,D1		; D1 <-- 2 * (PARAM[i] + PARAM[i+1])	MOVE.32	{A6}+T7,D4	; D4 <-- BX[i-1] ou BY[i]	MOVE.32	D4,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; SIGNE positif ?	JUMP,EQ	10$		; OUI => on ne fait rien	NEG.32	D4		; NON => prendre la ngation10$:	MOVE.32	D2,D3		; D3 <-- PARAM[i+1]	SR.32	#8.,D3		; formatage	CLR.32	D5	CALL	MUL64		; D4 <-- PARAM[i+1] * B[i-1] non format	MOVE.32	#256.,D3	CALL	DIV64		; D4 <-- PARAM[i+1] * B[i-1] format	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	20$	NEG.32	D420$:	SUB.32	D4,D1		; D1 <-- dnominateur	MOVE.32	D1,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; SIGNE positif ?	JUMP,EQ	30$		; OUI => on ne fait rien	NEG.32	D130$:	MOVE.32	{A6}+T1,D3	; D3 <-- PARAM[i]	MOVE.32	#65536.,D4	CLR.32	D5	CALL	MUL64		; formatage du numrateur	MOVE.32	D1,D3	CALL	DIV64		; D4 <-- BX[i]	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	40$	NEG.32	D440$:	MOVE.32	D4,{A6}+TAMP	; B[i] <-- D4	RET;---\; AI >		calcul des coefficients intermdiaires AX[i] et AY[i];---/;;;in : rien;out: rien;mod: FAI:1$:	MOVE.32	{A6}+T3,D1	; D1 <-- PX[i] ou PY[i] non format	MOVE.32	{A6}+T1,D3	; D3 <-- PARAM[i] format	MOVE.32	{A6}+T2,D4	; D4 <-- PARAM[i+1] format	MOVE.32	{A6}+T4,D2	; D2 <-- PX[i+1] ou PY[i+1] non format	SUB.32	D1,D2		; D2 <-- PX[i+1]-PX[i] non format	SUB.32 {A6}+T5,D1	; D1 <-- PX[i]-PX[i-1] non format	CLR.32	D5	MOVE.32	#65536.,D3	CALL	MUL64		; D5D4 <-- PARAM[i+1] * (2**16)	MOVE.32	{A6}+T1,D3	; D3 <-- PARAM[i]	CALL	DIV64		; D4 <-- PARAM[i+1] / PARAM[i]  format	MOVE.32	D4,D6		; D6 sauve D4	CLR.32	D5	MOVE.32	#65536.,D4	CALL	MUL64		; D5D4 <-- PARAM[i] * (2**16)	MOVE.32	{A6}+T2,D3 	; D3 <-- PARAM[i+1]	CALL	DIV64		; D4 <-- PARAM[i] / PARAM[i+1] format	MOVE.32	D2,D3		; D3 <-- PX[i+1]-PX[i]	MOVE.32	D3,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; SIGNE positif ?	JUMP,EQ	10$		; OUI => on ne fait rien	NEG.32	D3		; NON => prendre la ngation10$:	CLR.32	D5	CALL	MUL64		; D4 <-- (PARAM[i]/PARAM[i+1])*(PX[i+1]-PX[i])	COMP.32	#0,{A6}+SIGNE	; SIGNE positif ?	JUMP,EQ	20$		; OUI => on ne fait rien	NEG.32	D4		; NON => prendre la ngation20$:	MOVE.32	D4,{A6}+TAMP	; TAMP <-- D4 format	MOVE.32	D6,D4		; D4 <-- PARAM[i+1] / PARAM[i]	CLR.32	D5	MOVE.32	D1,D3		; D3 <-- PX[i] - PX[i+1]	MOVE.32	D3,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; SIGNE positif ?	JUMP,EQ	30$		; OUI => on ne fait rien	NEG.32	D3		; NON => prendre la ngation30$:	CALL	MUL64		; D4 <-- (PARAM[i+1]/PARAM[i])*(PX[i]-PX[i-1])				; format	COMP.32	#0,{A6}+SIGNE	; SIGNE positif ?	JUMP,EQ	40$		; OUI => on ne fait rien	NEG.32	D4		; NON => prendre la ngation40$:	ADD.32	{A6}+TAMP,D4	; D4 <-- TAMP + D4 format	MOVE.32	#3.,D3		; D3 <-- 3	CLR.32	D5	MOVE.32	D4,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; SIGNE positif	JUMP,EQ	50$		; OUI => on ne fait rien	NEG.32	D4		; NON => prendre la ngation50$:	CALL	MUL64		; D4 <-- 3 * D4	COMP.32	#0,{A6}+SIGNE	; SIGNE positif	JUMP,EQ	60$		; OUI => on ne fait rien	NEG.32	D4		; NON => prendre la ngation60$:	MOVE.32	D4,{A6}+TAMP	; TAMP <-- D4	MOVE.32	{A6}+T6,D3	; D3 <-- AX[i-1] ou AY[i-1]	MOVE.32	D3,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; SIGNE positif	JUMP,EQ	70$		; OUI => on ne fait rien	NEG.32	D3		; NON => prendre la ngation70$:	MOVE.32	{A6}+T2,D4	; D4 <-- PARAM[i+1]	SR.32	#8,D4		; formatage de D4 pour la multiplication	CLR.32	D5		;	CALL	MUL64		; D4 <-- PARAM[i+1] * AX[i-1]	MOVE.32	#256.,D3	CALL	DIV64		; formatage de D4	COMP.32	#0,{A6}+SIGNE	; SIGNE positif	JUMP,EQ	80$		; OUI => on ne fait rien	NEG.32	D4		; NON => prendre la ngation80$:	SUB.32	D4,{A6}+TAMP	; TAMP <-- numrateur	MOVE.32	{A6}+T1,D1	; D1 <-- PARAM[i]	ADD.32	{A6}+T2,D1	; D1 <-- PARAM[i] + PARAM[i+1]	SL.32	#1,D1		; D1 <-- 2 * (PARAM[i]+PARAM[i+1])	MOVE.32	{A6}+T7,D4	; D4 <-- BX[i-1] ou BY[i]	MOVE.32	D4,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; SIGNE positif ?	JUMP,EQ	81$		; OUI => on ne fait rien	NEG.32	D4		; NON => prendre la ngation81$:	MOVE.32	{A6}+T2,D3	; D3 <-- PARAM[i+1]	SR.32	#8,D3	CLR.32	D5	CALL	MUL64		; D4 <-- B[i] * PARAM[i+1] non format	MOVE.32	#256.,D3	CALL	DIV64		; D4 <-- B[i] * PARAM[i+1] format	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	82$	NEG.32	D482$:	SUB.32	D4,D1		; D1 <-- dnominateur	MOVE.32	{A6}+TAMP,D4	; D4 <-- numrateur	MOVE.32	D4,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; SIGNE positif ?	JUMP,EQ	83$	NEG.32	D483$:	MOVE.32	#65536.,D3	CLR.32	D5	CALL	MUL64		; formatage du numrateur	MOVE.32	D1,D3	CALL	DIV64		; D4 <-- AX[i] ou AY[i]	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	85$	NEG.32	D485$:	MOVE.32	D4,{A6}+TAMP	; sauvetage tamporaire de AX[i] ou AY[i]	RET;------\; ININC >	initialise DX1,DX2,DX3,DY1,DY2 et DY3;....../;;;in : rien;out: rien;mod: FININC:	MOVE.32	{A6}+TAMP,D0	; D0 <-- i	MOVE.32	#{A6}+AKX,A2	MOVE.32	{A2}+{D0},{A6}+T2; T2 <-- AKX[i]  (0|32)	MOVE.32	#{A6}+BKX,A2	MOVE.32	{A2}+{D0},{A6}+T3; T3 <-- BKX[i]  (0|32)	MOVE.32	#{A6}+PENTEX,A2	MOVE.32	{A2}+{D0},{A6}+T4; T4 <-- PENTEX[i]  (16|16)	CALL	CALCD1		; retourne DX1  (12|20)	MOVE.32	{A6}+T5,{A6}+DX1	CALL	CALCD23		; retourne DX2 (0|32) et DX3 (0|32)	MOVE.32	{A6}+T6,{A6}+DX2	MOVE.32	{A6}+T7,{A6}+DX3	MOVE.32	#{A6}+AKY,A2	MOVE.32	{A2}+{D0},{A6}+T2; T2 <-- AKY[i]  (0|32)	MOVE.32	#{A6}+BKY,A2	MOVE.32	{A2}+{D0},{A6}+T3; T3 <-- BKY[i]  (0|32)	MOVE.32	#{A6}+PENTEY,A2	MOVE.32	{A2}+{D0},{A6}+T4; T4 <-- PENTEY[i]  (16|16)	CALL	CALCD1		; retourne DY1  (12|20)	MOVE.32	{A6}+T5,{A6}+DY1	CALL	CALCD23		; retourne DY2 (0|32) et DY3 (0|32)	MOVE.32	{A6}+T6,{A6}+DY2	MOVE.32	{A6}+T7,{A6}+DY3	RET;-------\; CALCD1 > 	calcul les coefficients DX1 et DY1;......./;;;in : rien;out: rien;mod: FCALCD1:	PUSHM.32 D0|D1|D2|D3|D4	MOVE.32	{A6}+T1,D1	; D1 <-- valeur du paramtre t		MOVE.32	{A6}+T2,D3	; D3 <-- AKX[i] ou AKY[i]	MOVE.32	D3,{A6}+TAMPON	CALL	TSIGNE 	COMP.32	#0,{A6}+SIGNE	; AK[i] positif ?	JUMP,EQ	15$	NEG.32	D315$:	MOVE.32	D1,D4		; D4 <-- paramtre	CLR.32	D5	CALL	MUL64		; D5D4 <-- a * t  ( * 2**48)	MOVE.32	#65536.,D3	CALL	DIV64		; ( * 2**32)	SR.32	#8,D4		; format (8|24)	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	20$	NEG.32	D420$:	MOVE.32	{A6}+T3,D3	; D3 <-- BKX[i] ou BKY[i] (32|0)	MOVE.32	D3,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; BK[i] positif ?	JUMP,EQ	21$	ASR.32	#8,D3		; formatage pour 24 bits fractionnaires	JUMP	25$21$:	SR.32	#8,D3		; formatage pour 24 bits fractionnaires25$:	ADD.32	D3,D4		; D4 <-- (b + a * t)    (8|24)	MOVE.32	D4,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	27$	NEG.32	D427$:	MOVE.32	D1,D3		; D3 <-- PARAM[i]	CLR.32	D5	CALL	MUL64		; ( * 2**40)	MOVE.32	#65536.,D3	; divise par 2**16	CALL	DIV64		; D4 <-- t *(b + a * t)  ( * 2**24)	SR.32	#4,D4		; D4 en (12|20)	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	30$	NEG.32	D430$:	MOVE.32	{A6}+T4,D3	; D3 <-- PENTEX[i] ou PENTEY[i]  (16|16)	SL.32	#4,D3		; (12|20)	ADD.32	D3,D4		; D4 <-- c + t *(b + a * t)	MOVE.32	D4,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; D4 positif ?	JUMP,EQ	35$	NEG.32	D435$:	MOVE.32 D1,D3		; D3 <--PARAM[i]  (16|16)	CLR.32	D5	CALL	MUL64		; ( * 2**36)	MOVE.32	#65536.,D3	CALL	DIV64		; D4 <-- t *( c + t *(b + t * a))  ( * 2**20)	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	40$	NEG.32	D440$:	MOVE.32	D4,{A6}+T5	POPM.32 D0|D1|D2|D3|D4	RET;--------\; CALCD23 >	calcul les coefficients DX2,DX3,DY2 et DY3;......../;;;in : DO;out: rien;mod: FCALCD23:	PUSHM.32 D2|D3|D4|D5	MOVE.32	{A6}+T1,D2	; D2 <-- paramtre t (16|16)	MOVE.32	{A6}+T2,D4	; D4 <-- AKX[i] ou AKY[i] (0|32)	MOVE.32	D4,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; AK[i] positif ?	JUMP,EQ	10$	NEG.32	D410$:	CLR.32	D5	MOVE.32	D2,D3		; D3 <-- t	CALL	MUL64		; D5D4 <-- AK[i] * t  ( * 2**48)	MOVE.32	#65536.,D3	CALL	DIV64		; D4 <-- AK[i] * t  (0|32)	MOVE.32	D2,D3	CLR.32	D5	CALL	MUL64		; D5D4 <-- AK[i] * t**2  ( * 2**48)	MOVE.32	#65536.,D3	CALL	DIV64		; D4 <-- AK[i] * t**2  (0|32)	MOVE.32	D2,D3	CLR.32	D5	CALL	MUL64		; D5D4 <-- AK[i] * t**3   ( * 2**48)	MOVE.32	#65536.,D3	CALL	DIV64		; D4 <-- AK[i] * t**3  (0|32)	MOVE.32	#6.,D3	CLR.32	D5	CALL	MUL64		; D4 <-- 6 * (AK[i] * t**3)  (0|32)	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	20$	NEG.32	D420$:	MOVE.32	D4,{A6}+T7	; T7 <-- D3  (0|32)	MOVE.32	{A6}+T3,D4	; D4 <-- BKX[i] ou BKY[i]	MOVE.32	D4,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; BK[i] positif ?	JUMP,EQ	30$	NEG.32	D430$:	CLR.32	D5	MOVE.32	D2,D3	CALL	MUL64		; D5D4 <-- BK[i] * t  (0|64)	MOVE.32	#65536.,D3	CALL	DIV64		; D4 <-- BK[i] * t  (0|32)	MOVE.32	D2,D3	CLR.32	D5	CALL	MUL64		; D5D4 <-- BK[i] * t**2  ( * 2**48)	MOVE.32	#65536.,D3	CALL	DIV64		; D4 <-- BK[i] * t**2  (0|32)	SL.32	#1,D4		; D4 <-- 2 * BK[i] * t**2  (0|32)	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	40$	NEG.32	D440$:	ADD.32	{A6}+T7,D4	MOVE.32	D4,{A6}+T6	; T6 <-- D2  (0|32)	POPM.32 D2|D3|D4|D5	RET;-------\                          t[n]                           1; DETCO1 > 	 3*(P[1] - P[0])* _______ - 3* (P[n-1] - P[n]) * ____;......./			  t[1]**2                        t[n];;;in : rien;out: rien;mod: FDETCO1:	MOVE.32	{A6}+T2,D1	; D1 <-- PX[1] ou PY[1]	SUB.32	{A6}+T1,D1	; D1 <-- P[1] - P[0]	MUL.A16	#3,D1		; D1 <-- 3 * (P[1] - P[0]) (32|0)	MOVE.32 {A6}+T5,D3	; D3 <-- PARAM[n]  (16|16)	MOVE.32	#65536.,D4	CLR.32	D5	CALL	MUL64		; formatage pour la division	MOVE.32	{A6}+T6,D3	; D3 <-- PARAM[1]  (16|16)	CALL	DIV64		; D4 <-- PARAM[n] / PARAM[1]  (16|16)	MOVE.32	#65536.,D3	CLR.32	D5	CALL	MUL64		; formatage de D4 pour la division	MOVE.32	{A6}+T6,D3	; D3 <-- PARAM[1]	CALL	DIV64		; D4 <-- PARAM[n] / PARAM[1]**2  (16|16)	MOVE.32	D1,D3		; D3 <-- 3 * (P[1] - P[0])  (32|0)	MOVE.32	D3,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; D3 positif ?	JUMP,EQ	10$	NEG.32	D310$:	CLR.32	D5	CALL	MUL64	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	20$	NEG.32	D420$:	MOVE.32	D4,D6		; D6 <-- 3*(P[1] - P[0]) * (t[n]/t[1]**2)				; (16|16)	MOVE.32	{A6}+T3,D1	; D1 <-- PX[n-1] ou PY[n-1]	SUB.32	{A6}+T4,D1	; D1 <-- P[n-1] - P[n]	MUL.A16	#3,D1		; D1 <-- 3 * (P[n-1] - P[n])	MOVE.32	D1,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; D1 positif ?	JUMP,EQ	30$	NEG.32	D130$:	SL.32	#8,D1		; (24|8)	SL.32	#8,D1		; (16|16)	MOVE.32	D1,D3	MOVE.32	#65536.,D4	CLR.32	D5	CALL	MUL64		; formatage pour la division	MOVE.32	{A6}+T5,D3	; D3 <-- PARAM[n]  (16|16)	CALL	DIV64		; D4 <-- (P[n-1] - P[n]) / PARAM[n] (16|16)	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	40$	NEG.32	D440$:	SUB.32	D4,D6		; D4 contient le rsultat CO1	MOVE.32	D6,{A6}+T7	RET;-------\            t[i]                       t[i+1]; DETCO2 >   3 * {  _______ * (P[i+1] - P[i]) + _______ * (P[i] - P[i-1]) };......./            t[i+1]                       t[i];;;in : rien;out: rien;mod: FDETCO2:	MOVE.32	{A6}+T4,D1	; D1 <-- PX[i+1] ou PY[i+1]	SUB.32	{A6}+T3,D1	; D1 <-- P[i+1] - P[i]	MOVE.32	{A6}+T1,D3	; D3 <-- PARAM[i]	MOVE.32	#65536.,D4	CLR.32	D5	CALL	MUL64		; formatage pour la division	MOVE.32	{A6}+T2,D3	; D3 <-- PARAM[i+1]	CALL	DIV64		; D4 <-- PARAM[i] / PARAM[i+1]  (16|16)	MOVE.32	D1,D3		; D3 <-- P[i+1] - P[i]  (32|0)	MOVE.32	D3,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; D3 positif ?	JUMP,EQ	10$	NEG.32	D310$:	CLR.32	D5	CALL	MUL64	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	20$	NEG.32	D420$:	MOVE.32	D4,D6		; D6 <-- (P[i+1] - P[i]) * (t[i] / t[i+1])				; (16|16)	MOVE.32	{A6}+T3,D1	; D1 <-- PX[i] ou PY[i]	SUB.32	{A6}+T5,D1	; D1 <-- P[i] - P[i-1]	MOVE.32	{A6}+T2,D3	; D3 <-- PARAM[i+1]	MOVE.32	#65536.,D4	CLR.32	D5	CALL	MUL64		; formatage pour la division	MOVE.32	{A6}+T1,D3	; D3 <-- PARAM[i]	CALL	DIV64		; D4 <-- PARAM[i+1] / PARAM[i]  (16|16)	MOVE.32	D1,D3		; D3 <-- P[i] - P[i-1]  (32|0)	MOVE.32	D3,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; D3 positif ?	JUMP,EQ	30$	NEG.32	D330$:	CLR.32	D5	CALL	MUL64	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	40$	NEG.32	D440$:	ADD.32	D6,D4		; D4 contient le rsultat CO2[i]/3	MOVE.32	D4,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; D4 positif ?	JUMP,EQ	50$	NEG.32	D450$:	CLR.32	D5	MOVE.32	#3.,D3	CALL	MUL64		; D4 contient le rsultat en valeur absolue	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	60$	NEG.32	D460$:	MOVE.32	D4,{A6}+T6	; T6 <-- DO2[i]  (16|16)	RET;-------\; DETCO3 >	2 * (PARAM[i] + PARAM[i+1]);......./;;;in : rien;out: rien;mod: FDETCO3:	MOVE.32	{A6}+T1,D1	; D1 <-- PARAM[i]	ADD.32	{A6}+T2,D1	; D1 <-- PARAM[i] + PARAM[i+1]	SL.32	#1,D1		; D1 <-- 2 * (PARAM[i] + PARAM[i+1])	MOVE.32	D1,{A6}+T3	; retourne CO3[i] dans T3	RET;------\; DETK3 >	K3[i] = CO3[i] - PARAM[i] * K2[i+1];....../;;;in : rien;out: rien;mod: FDETK3:	MOVE.32	{A6}+T2,D3	; D3 <-- PARAM[i]	MOVE.32	{A6}+T3,D4	; D4 <-- K2[i+1]	MOVE.32	D4,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; K2[i+1] positif ?	JUMP,EQ	10$	NEG.32	D410$:	CLR.32	D5	CALL	MUL64		; D5D4 <-- K2[i+1] * PARAM[i]  ( * 2**32)	MOVE.32	#65536.,D3	CALL	DIV64		; D4 <-- K2[i+1] * PARAM[i]  (16|16)	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	20$	NEG.32	D420$:	MOVE.32	{A6}+T1,D1	; D1 <-- CO3[i]	SUB.32	D4,D1		; D1 <-- CO3[i] - K2[i+1]*PARAM[i] (16|16)	MOVE.32	D1,{A6}+T7	RET;------\                 CO2[i] - PARAM[i]*K1[i+1]; DETK1 >	K1[i] = ____________________________;....../                         K3[i];;;in : rien;out: rien;mod: FDETK1:	MOVE.32	{A6}+T2,D3	; D3 <-- PARAM[i]	MOVE.32	{A6}+T5,D4	; D4 <-- K1[i+1]	MOVE.32	D4,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; K1[i+1] positif ?	JUMP,EQ	10$	NEG.32	D410$:	CLR.32	D5	CALL	MUL64		; D5D4 <-- K1[i+1] * PARAM[i]  ( * 2**32)	MOVE.32	#65536.,D3	CALL	DIV64		; D4 <-- K1[i+1] * PARAM[i]  (16|16)	COMP.32	#0,{A6}+SIGNE	JUMP,EQ	20$	NEG.32	D420$:	MOVE.32	{A6}+T4,D3	; D3 <-- CO2[i]	SUB.32	D4,D3		; D3 <-- CO2[i] - K1[i+1]*PARAM[i] (16|16)	MOVE.32	#0,{A6}+TAMP	; initialise TAMP	MOVE.32	D3,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; D3 positif ?	JUMP,EQ	30$	NEG.32	D3	MOVE.32	#1,{A6}+TAMP	; => D3 ngatif30$:	MOVE.32	{A6}+T7,D6	; D6 <-- K3[i]	MOVE.32	D6,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; K3[i] positif ?	JUMP,EQ	40$	NEG.32	D6	COMP.32	#0,{A6}+TAMP	; D3 positif ?	JUMP,EQ	35$	MOVE.32	#0,{A6}+TAMP	; D3 et D6 sont ngatifs	JUMP	40$35$:	MOVE.32	#1,{A6}+TAMP	; D3 positif et D6 ngatif40$:	CLR.32	D5	MOVE.32	#65536.,D4	CALL	MUL64		; formatage pour la division	MOVE.32	D6,D3	CALL	DIV64		; D4 <-- K1[i] en absolu	COMP.32	#0,{A6}+TAMP	JUMP,EQ	50$	NEG.32	D450$:	MOVE.32	D4,{A6}+T6	RET;-------\; DETCK1 >	CK1[i] = CK1[i+1] * K2[i+1];......./;;;in : rien;out: rien;mod: FDETCK1:	MOVE.32	#0,{A6}+TAMP	; initialise le testeur de signe	MOVE.32	{A6}+T2,D3	; D3 <-- K2[i+1]	MOVE.32	D3,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; K2[i+1] positif ?	JUMP,EQ	10$	NEG.32	D3	MOVE.32	#1,{A6}+TAMP	; => K2[i+1] ngatif10$:	MOVE.32	{A6}+T1,D4	; D4 <-- CK1[i+1]	MOVE.32	D4,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; CK1[i+1] positif ?	JUMP,EQ	30$	NEG.32	D4	COMP.32	#0,{A6}+TAMP	JUMP,EQ	20$	MOVE.32	#0,{A6}+TAMP	; K2[i+1] ng. et CK1[i+1] ng.	JUMP	30$20$:	MOVE.32	#1,{A6}+TAMP	; K2[i+1] pos. et CK1[i+1] ng.30$:	CLR.32	D5	CALL	MUL64		; D5D4 <-- K2[i+1] * CK1[i+1]  ( * 2**32)	MOVE.32	#65536.,D3	CALL	DIV64		; D4 <-- K2[i+1] * CK1[i+1]  (16|16)	COMP.32	#0,{A6}+TAMP	JUMP,EQ	40$	NEG.32	D440$:	MOVE.32	D4,{A6}+T3	; T3 <-- CK1[i]	RET;-------\; DETCK2 >	CK2[i] = CK2[i+1] - CK1[i+1] * K1[i+1];......./;;;in : rien;out: rien;mod: FDETCK2:	MOVE.32	#0,{A6}+TAMP	; initialise le testeur de signe	MOVE.32	{A6}+T4,D3	; D3 <-- K1[i+1]	MOVE.32	D3,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; K1[i+1] positif ?	JUMP,EQ	10$	NEG.32	D3	MOVE.32	#1,{A6}+TAMP	; => K1[i+1] ngatif10$:	MOVE.32	{A6}+T1,D4	; D4 <-- CK1[i+1]	MOVE.32	D4,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; CK1[i+1] positif ?	JUMP,EQ	30$	NEG.32	D4	COMP.32	#0,{A6}+TAMP	JUMP,EQ	20$	MOVE.32	#0,{A6}+TAMP	; K1[i+1] ng. et CK1[i+1] ng.	JUMP	30$20$:	MOVE.32	#1,{A6}+TAMP	; K1[i+1] pos. et CK1[i+1] ng.30$:	CLR.32	D5	CALL	MUL64		; D5D4 <-- K1[i+1] * CK1[i+1]  ( * 2**32)	MOVE.32	#65536.,D3	CALL	DIV64		; D4 <-- K1[i+1] * CK1[i+1]  (16|16)	COMP.32	#0,{A6}+TAMP	JUMP,EQ	40$	NEG.32	D440$:	MOVE.32	{A6}+T5,D3	; D3 <-- CK2[i+1]  (16|16)	SUB.32	D4,D3		; D3 <-- CK2[i+1] - K1[i+1] * CK1[i+1]	MOVE.32	D3,{A6}+T5	; T5 <-- CK2[i]	RET;-------\; DETRAP >	retourne PARAM[n] / PARAM[1];......./;;;in : rien;out: rien;mod: FDETRAP:	PUSHM.32 D0|D3|D4|D5|A0	MOVE.32	{A6}+NBPOINTS,D0	SUB.32	#4.,D0		; positionne D0 sur le dernier point	MOVE.32	#{A6}+PARAM,A0	MOVE.32	{A0}+{D0},D3	; D3 <-- PARAM[n]	MOVE.32	#65536.,D4	CLR.32	D5	CALL	MUL64		; prparation pour la division	MOVE.32	#4.,D0		; D0 <-- i=1	MOVE.32	{A0}+{D0},D3	; D3 <-- PARAM[1]	CALL	DIV64		; D4 <-- PARAM[n] / PARAM[1]	MOVE.32	D4,{A6}+T7	POPM.32 D0|D3|D4|D5|A0	RET;---------\; DETPENTC >	retourne PENTEX[i] ou PENTEY[i];........./;;;in : rien;out: rien;mod: FDETPENTC:	MOVE.32	#0,{A6}+TAMP	; initialise le testeur de signe	MOVE.32	{A6}+T1,D3	; D3 <-- PENTEX[i] ou PENTEY[i]	MOVE.32	D3,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; PENTE[i] positif ?	JUMP,EQ	10$	NEG.32	D3	MOVE.32	#1,{A6}+TAMP	; => PENTE[i] ngatif10$:	MOVE.32	{A6}+T2,D4	; D4 <-- K2[i+1]	MOVE.32	D4,{A6}+TAMPON	CALL	TSIGNE	COMP.32	#0,{A6}+SIGNE	; K2[i+1] positif ?	JUMP,EQ	30$	NEG.32	D4	COMP.32	#0,{A6}+TAMP	JUMP,EQ	20$	MOVE.32	#0,{A6}+TAMP	; PENTE[i] ng. et K2[i+1] ng.	JUMP	30$20$:	MOVE.32	#1,{A6}+TAMP30$:	CLR.32	D5	CALL	MUL64	MOVE.32	#65536.,D3	CALL	DIV64		; D4 <-- K2[i+1] * PENTE[i]  (16|16)	COMP.32	#0,{A6}+TAMP	JUMP,EQ	40$	NEG.32	D440$:	MOVE.32	{A6}+T3,D3	; D3 <-- K1X[i+1] ou K1Y[i+1]	ADD.32	D3,D4	MOVE.32	D4,{A6}+T1	; T1 <-- PENTE[i+1]	RET;-------\; RACINE >	effectue la racine carre pour le paramtre de la spline;......./;;;in :rien;out:rien;mod:FRACINE:	MOVE.32	{A6}+TAMPON,D3	; sort le nombre "a";	COMP.32	#16777216.,D3	; teste si D3 > 2**20;	JUMP,LT	10$;	l'cart entre deux points est trop grand !;10$:	SL.32	#8,D3		; format pour 8 bits fractionnaires	MOVE.32	D3,{A6}+TAMP	; PARAM <-- a	SR.32	#1,D3		; D3 <-- a/2	MOVE.32 #30.,D6BOUCLE:	MOVE.32	{A6}+TAMP,D1	; D1 <-- x(k)	MOVE.32	D1,D2		; D2 <-- x(k)	SR.32	#1.,D2		; D2 <-- x(k)/2	CLR.32	D5	MOVE.32	#256.,D4	CALL	MUL64		; formatage du numrateur D5D4 = D3 * D4 + D5	PUSH.32	D3		; sauve a/2	MOVE.32	D1,D3		; charge le dnominateur	CALL	DIV64		; D4 <-- a / (2 * x(k))	POP.32	D3	ADD.32	D4,D2		; D2 <-- x(k+1) = x(k)/2 + a / (2 * x(k))	MOVE.32	D2,{A6}+TAMP	; sauvetage de PARAM dans un format ayant les	DEC.32	D6		; 8 bits de poids faibles pour les nombres	JUMP,NE	BOUCLE		; fractionnaires	SL.32	#8,D2	MOVE.32	D2,{A6}+TAMP	RET;------\; DIV64 >;....../;;;in : D5D4 : D3 = D4 et reste dans D5;out: D5.32,D4.32;mod: D5,D4DIV64:	TEST.32	D3	JUMP,ZS	DIVERR	; division par zro	PUSH.32	D0	MOVE.32	#D'32-1,D0DIV642:	SETX	RLX.32	D4	RLX.32	D5	; *2+1	JUMP,CS	DIVER1	; overflow	SUB.32	D3,D5	JUMP,HS	DIV644	ADD.32	D3,D5	TCLR.32	D4:#0DIV644:	DECJ.16,NMO	D0,DIV642	POP.32	D0	CLRC	RETDIVER1:	POP.32	D0DIVERR:	SETC	RET;------\; MUL64 >;....../;;;in :D5D4 = D3 * D4 + D5;out: D5.32,D4.32;mod: D5,D4MUL64:	PUSH.32	D3	SUB.32	#4,SP		; initialise l'aire de production	CLR.32	{-SP}	MOVE.32	D3,{-SP}	; sauve une copie du multiplicande	MUL.16	D4,D3		; multiplie la partie de poids faible	MOVE.32	D3,{SP}+8	MOVE.16 {SP},D3		;multiplicande de poids fort	MUL.16	D4,D3	ADD.32	D3,{SP}+6	SWAP.32	D4	MOVE.16	{SP}+2,D3	MUL.16	D4,D3	ADD.32	D3,{SP}+6	JUMP,CC	MUL64A	ADD.16	#1,{SP}+4MUL64A:	MOVE.32	{SP+},D3	SWAP.32	D3	MUL.16	D4,D3	ADD.32	{SP+},D3	MOVE.32	{SP+},D4	ADD.32	D5,D4	JUMP,CC	MUL64B	ADD.32	#1,D3MUL64B:	MOVE.32	D3,D5	POP.32	D3	RET		;-------\; TSIGNE >	teste si un nombre est ngatif;......./;;;in : rien;out: rien;mod: FTSIGNE:	MOVE.32	#0,{A6}+SIGNE	; initialise  positif	COMP.32	#0,{A6}+TAMPON	; nombre positif ?	JUMP,GE	10$		; OUI => ne fait rien	MOVE.32	#1,{A6}+SIGNE	; NON => signe ngatif10$:	RET	.START	START	.END